/// <summary>
///
/// </summary>
/// <param name="_sender"></param>
/// <param name="_eventArgs"></param>
[DataEventHandler(tableStr(PurchPurchaseAgreementLineV2Entity), DataEventType::PostedLoad)]
public static void PurchPurchaseAgreementLineV2Entity_onPostedLoad(Common _sender, DataEventArgs _eventArgs)
{

    PurchPurchaseAgreementLineV2Entity purchPurchaseAgreementLineV2Entity = _sender as PurchPurchaseAgreementLineV2Entity;

    AgreementHeaderDefault agreementHeaderDefault;
    ETG_PurchaseAgreementHeader ETG_PurchaseAgreementHeaderOrg;
    LogisticsPostalAddress logisticsPostalAddress, logisticsPostalAddressLoc,logisticsPostalAddressbank,logisticsPostalAddressseller;
    AgreementLine agreementLineOrg;
    PaymTerm paymTerm;
    InventTable inventTable;
    VendTable vendTable;
    CompanyInfo companyInfo; 
    PurchAgreementHeader purchAgreementHeader;
    ETG_PurchTableTrade ETG_PurchTableTrade;
    PurchTable   purchtable;
    BankAccountTable BankAccountTable,BankAccountTablebuyer;
    VendBankAccount vendBankAccount;
    ETG_CommodityMappingTable ETG_CommodityMappingTable;
    ETG_PlaceOfDischarge ETGPlaceOfDischargeCountry;
    ETG_PlaceOfLoading ETGPlaceOfLoadingCountry;

    select * from agreementHeaderDefault
        where agreementHeaderDefault.AgreementHeader == purchPurchaseAgreementLineV2Entity.Agreement;

    purchPurchaseAgreementLineV2Entity.DeliveryMode = agreementHeaderDefault.DeliveryMode;
    purchPurchaseAgreementLineV2Entity.DeliveryTerm = agreementHeaderDefault.DeliveryTerm;
    purchPurchaseAgreementLineV2Entity.PaymentTerms = agreementHeaderDefault.PaymentTerms;
    purchPurchaseAgreementLineV2Entity.ETGReference  = agreementHeaderDefault.ExternalReference;
    select * from ETG_PurchaseAgreementHeaderOrg
        where ETG_PurchaseAgreementHeaderOrg.PurchAgreementId == purchPurchaseAgreementLineV2Entity.PurchaseAgreementId;

    purchPurchaseAgreementLineV2Entity.BuyerBank = ETG_PurchaseAgreementHeaderOrg.BuyerBank;
    purchPurchaseAgreementLineV2Entity.SellerBank = ETG_PurchaseAgreementHeaderOrg.SellerBank;
    purchPurchaseAgreementLineV2Entity.PortOfLoading = ETG_PurchaseAgreementHeaderOrg.PortOfLoading;
    purchPurchaseAgreementLineV2Entity.PortOfDischarge = ETG_PurchaseAgreementHeaderOrg.PortOfDischarge;
    purchPurchaseAgreementLineV2Entity.PortOfLoadingDesc = ETG_PurchaseAgreementHeaderOrg.PortOfLoadingDesc;
    purchPurchaseAgreementLineV2Entity.PortOfDischargeDesc = ETG_PurchaseAgreementHeaderOrg.PortOfDischargeDesc;

    select * from ETGPlaceOfDischargeCountry
        where ETGPlaceOfDischargeCountry.PlaceOfDischarge == purchPurchaseAgreementLineV2Entity.PortOfDischarge;

    purchPurchaseAgreementLineV2Entity.ETGPlaceOfDischargeCountry = ETGPlaceOfDischargeCountry.Country;

    select * from ETGPlaceOfLoadingCountry
        where ETGPlaceOfLoadingCountry.PlaceOfLoading == purchPurchaseAgreementLineV2Entity.PortOfLoading;

    purchPurchaseAgreementLineV2Entity.ETGPlaceOfLoadingCountry = ETGPlaceOfLoadingCountry.Country;

    purchPurchaseAgreementLineV2Entity.BuyyerAccountNum = ETG_PurchaseAgreementHeaderOrg.BuyerAccountNum;
    purchPurchaseAgreementLineV2Entity.SellerAccountNum = ETG_PurchaseAgreementHeaderOrg.SellerAccountNum;
    purchPurchaseAgreementLineV2Entity.BuyyerName = ETG_PurchaseAgreementHeaderOrg.buyerName();
    purchPurchaseAgreementLineV2Entity.SellerName = ETG_PurchaseAgreementHeaderOrg.sellerName();
    purchPurchaseAgreementLineV2Entity.Notifytodifferentparty = ETG_PurchaseAgreementHeaderOrg.Notifytodifferentparty;
    purchPurchaseAgreementLineV2Entity.NotifyPartyName = ETG_PurchaseAgreementHeaderOrg.Name;
    purchPurchaseAgreementLineV2Entity.NotifyPartyAddress = ETG_PurchaseAgreementHeaderOrg.Address;
    purchPurchaseAgreementLineV2Entity.Consignee = ETG_PurchaseAgreementHeaderOrg.Consignee;
    purchPurchaseAgreementLineV2Entity.Shipment = ETG_PurchaseAgreementHeaderOrg.DeliveryDescription;
    purchPurchaseAgreementLineV2Entity.PackingGroup = ETG_PurchaseAgreementHeaderOrg.PackingGroup;
    purchPurchaseAgreementLineV2Entity.PackingNotes = ETG_PurchaseAgreementHeaderOrg.Notes;
    purchPurchaseAgreementLineV2Entity.Through = ETG_PurchaseAgreementHeaderOrg.Through;
    purchPurchaseAgreementLineV2Entity.Shipper = ETG_PurchaseAgreementHeaderOrg.ShipperBuyer;
    purchPurchaseAgreementLineV2Entity.ShipmentFrom = ETG_PurchaseAgreementHeaderOrg.FromDatePort;
    purchPurchaseAgreementLineV2Entity.ShipmentTo = ETG_PurchaseAgreementHeaderOrg.ToDatePort;
    purchPurchaseAgreementLineV2Entity.AgreementType = ETG_PurchaseAgreementHeaderOrg.AgreementType;
    purchPurchaseAgreementLineV2Entity.ETG_QuantityConditions  = ETG_PurchaseAgreementHeaderOrg.QuantityConditions;
    purchPurchaseAgreementLineV2Entity.EtgFixation = ETG_PurchaseAgreementHeaderOrg.Fixation;
    purchPurchaseAgreementLineV2Entity.EtgCONTAINERID = ETG_PurchaseAgreementHeaderOrg.VESSELSAILED;

    purchPurchaseAgreementLineV2Entity.ThroughName = VendTable::find(purchPurchaseAgreementLineV2Entity.Through).name();

    select * from logisticsPostalAddress
        where logisticsPostalAddress.RecId == ETG_PurchaseAgreementHeaderOrg.BuyerDeliveryAddress;

   // purchPurchaseAgreementLineV2Entity.BuyyerBankAddress = logisticsPostalAddress.Address;
    purchPurchaseAgreementLineV2Entity.BuyyerAddress = logisticsPostalAddress.Address;

    select * from logisticsPostalAddressLoc
        where logisticsPostalAddressLoc.RecId == ETG_PurchaseAgreementHeaderOrg.SellerDeliveryAddress;

   // purchPurchaseAgreementLineV2Entity.SellerBankAddress = logisticsPostalAddressLoc.Address;
    purchPurchaseAgreementLineV2Entity.SellerAddress = logisticsPostalAddressLoc.Address;

    select * from agreementLineOrg
        where agreementLineOrg.Agreement == purchPurchaseAgreementLineV2Entity.Agreement;

    purchPurchaseAgreementLineV2Entity.ItemName = agreementLineOrg.name();
    purchPurchaseAgreementLineV2Entity.PriceTxt = agreementLineOrg.ETGPriceCondition;
    purchPurchaseAgreementLineV2Entity.ETGFinalPlaceOfDelivery = agreementLineOrg.ETGFinalPlaceOfDelivery;

    select * from paymTerm
        where paymTerm.PaymTermId == purchPurchaseAgreementLineV2Entity.PaymentTerms;

    purchPurchaseAgreementLineV2Entity.PaymemtTermsDescription = paymTerm.Description;
    purchPurchaseAgreementLineV2Entity.PaymTermTxt = paymTerm.PaymTermTxt;

    select * from inventTable
        where inventTable.ItemId == purchPurchaseAgreementLineV2Entity.ItemNumber;

    purchPurchaseAgreementLineV2Entity.ETGMainCommodity = inventTable.ETGCommodity;

    select firstonly ETG_CommodityMappingTable
        where ETG_CommodityMappingTable.MainCommodity == inventTable.ETGCommodity;

    purchPurchaseAgreementLineV2Entity.ETGCommodity = ETG_CommodityMappingTable.Commodity;

    select * from vendTable
        where vendTable.AccountNum == purchPurchaseAgreementLineV2Entity.VendAccount;

    purchPurchaseAgreementLineV2Entity.VendName = vendTable.vendorName();
    purchPurchaseAgreementLineV2Entity.VendorAddress = vendTable.postalAddress().Address;
    purchPurchaseAgreementLineV2Entity.Email = VendTable::find(purchPurchaseAgreementLineV2Entity.VendAccount).email();

    DirPartyTable       dirPartyTable;
    TaxInformation_IN   taxInformation_IN;
    DirPartyLocation    dirPartyLocation;
    TaxRegistration     taxRegistration;
    TaxRegistrationType taxRegistrationType;


    select * from dirPartyTable
        where dirPartyTable.RecId == vendTable.Party;

    taxInformation_IN = TaxInformation_IN::findDefaultbyLocation(LogisticsPostalAddress::findRecId(dirPartyTable.PrimaryAddressLocation).Location);

    purchPurchaseAgreementLineV2Entity.TIN = TaxRegistrationNumbers_IN::find(taxInformation_IN.TIN).RegistrationNumber;

    purchPurchaseAgreementLineV2Entity.VendCountryRegionId = vendTable.postalAddress().CountryRegionId;

    select * from companyInfo where companyInfo.DataArea == curExt();

    purchPurchaseAgreementLineV2Entity.CompanyName = companyInfo.name();

    select * from dirPartyLocation
        where dirPartyLocation.Party == dirPartyTable.RecId
        && dirPartyLocation.IsPrimary == NoYes::Yes;

    while select * from taxRegistration
        where taxRegistration.DirPartyLocation == dirPartyLocation.RecId
    {
        select * from taxRegistrationType
        where taxRegistrationType.RecId == taxRegistration.TaxRegistrationTypeApplicabilityRule;

        if(taxRegistrationType.TaxRegstrationType == "IEC")
        {                
            purchPurchaseAgreementLineV2Entity.ETGIECCode = taxRegistration.RegistrationNumber;
        }
        if(taxRegistrationType.TaxRegstrationType == "FSSAI")
        {
            purchPurchaseAgreementLineV2Entity.ETGFSSAIID = taxRegistration.RegistrationNumber;
        }
        if(taxRegistrationType.TaxRegstrationType == "GST")
        {
            purchPurchaseAgreementLineV2Entity.ETGGSTIN = taxRegistration.RegistrationNumber;
        }
    }
    if(!purchPurchaseAgreementLineV2Entity.ETGIECCode)
    {
        purchPurchaseAgreementLineV2Entity.ETGIECCode = vendTable.ETGIECCode;
    }
    if(!purchPurchaseAgreementLineV2Entity.ETGFSSAIID)
    {
        purchPurchaseAgreementLineV2Entity.ETGFSSAIID = vendTable.ETGFSSAIID;
    }
    if(!purchPurchaseAgreementLineV2Entity.ETGGSTIN)
    {
        purchPurchaseAgreementLineV2Entity.ETGGSTIN = vendTable.ETGGSTIN;
    }
    select * from purchAgreementHeader
        where purchAgreementHeader.PurchNumberSequence == purchPurchaseAgreementLineV2Entity.PurchaseAgreementId;
    select * from purchtable where 
             purchtable.MatchingAgreement == purchAgreementHeader.RecId;
    select * from  ETG_PurchTableTrade where
        ETG_PurchTableTrade.PurchId == purchTable.PurchId;

    purchPurchaseAgreementLineV2Entity.ETGPOType = ETG_PurchTableTrade.OrderType;

    select firstonly vendBankAccount where vendBankAccount.AccountID == purchPurchaseAgreementLineV2Entity.SellerBank
                                        && vendBankAccount.VendAccount == purchPurchaseAgreementLineV2Entity.VendAccount;

    purchPurchaseAgreementLineV2Entity.ETGSellerBankName = vendBankAccount.Name;
    purchPurchaseAgreementLineV2Entity.ETGIbanNumber = vendBankAccount.BankIBAN;
    purchPurchaseAgreementLineV2Entity.ETGSwiftCode = vendBankAccount.SWIFTNo;
    purchPurchaseAgreementLineV2Entity.ETGAccountNumber = vendBankAccount.AccountNum;
    purchPurchaseAgreementLineV2Entity.ETGIfsc = vendBankAccount.ETGIfsc;
   // purchPurchaseAgreementLineV2Entity.ETGCorrespondingBank = vendBankAccount.corre;

    select * from logisticsPostalAddressbank where logisticsPostalAddressbank.Location == vendBankAccount.Location;
    purchPurchaseAgreementLineV2Entity.SellerBankAddress = logisticsPostalAddressbank.Address;

    if(!purchPurchaseAgreementLineV2Entity.SellerBankAddress)
    {
        select * from logisticsPostalAddressbank where logisticsPostalAddressbank.Location == str2Int64(vendBankAccount.AccountID);
        purchPurchaseAgreementLineV2Entity.SellerBankAddress = logisticsPostalAddressbank.Address;
    }

    select firstonly  BankAccountTablebuyer where BankAccountTablebuyer.AccountID == purchPurchaseAgreementLineV2Entity.BuyerBank;

    purchPurchaseAgreementLineV2Entity.ETGBuyerBankName = BankAccountTablebuyer.Name;
    purchPurchaseAgreementLineV2Entity.ETGIbanNumberBuyer = BankAccountTablebuyer.IBAN;
    purchPurchaseAgreementLineV2Entity.ETGSwiftCodeBuyer = BankAccountTablebuyer.SWIFTNo;
    purchPurchaseAgreementLineV2Entity.ETGAccountNumberbuyer = BankAccountTablebuyer.AccountNum;
    purchPurchaseAgreementLineV2Entity.ETGCorrespondingBankbuyer = BankAccountTablebuyer.ETGCorrespondentBank;

    select * from logisticsPostalAddressseller where logisticsPostalAddressseller.Location == BankAccountTablebuyer.Location;
    purchPurchaseAgreementLineV2Entity.BuyyerBankAddress = logisticsPostalAddressseller.Address;



}
